101→        offsetHours()
102→        outputIfNeeded(outputMinute) {
103→            if (useSeparator) {
104→                char(':')
105→            }
106→            offsetMinutesOfHour()
107→            outputIfNeeded(outputSecond) {
108→                if (useSeparator) {
