163→
164→    fun toUtcOffset(): UtcOffset {
165→        val sign = if (isNegative == true) -1 else 1
166→        return UtcOffset(
167→            totalHoursAbs?.let { it * sign }, minutesOfHour?.let { it * sign }, secondsOfMinute?.let { it * sign }
168→        )
169→    }
