internal val ISO_DATE by lazy {
    LocalDateFormat.build { year(); char('-'); monthNumber(); char('-'); dayOfMonth() }
}
internal val ISO_DATE_BASIC by lazy {
    LocalDateFormat.build { year(); monthNumber(); dayOfMonth() }
}

