package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Tests that error messages use user-facing API names instead of internal field names.
 */
class ErrorMessageTest {

    @Test
    fun testOffsetHoursErrorMessage() {
        val format = DateTimeComponents.Format {
            offsetHours()
        }

        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                // Not setting offsetHours
            }
        }

        assertTrue(
            exception.message!!.contains("offsetHours"),
            "Expected error message to contain 'offsetHours', but was: ${exception.message}"
        )
        assertFalse(
            exception.message!!.contains("totalHoursAbs"),
            "Expected error message NOT to contain internal name 'totalHoursAbs', but was: ${exception.message}"
        )
    }

    @Test
    fun testOffsetMinutesOfHourErrorMessage() {
        val format = DateTimeComponents.Format {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
        }

        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                offsetHours = 5
                // Not setting offsetMinutesOfHour
            }
        }

        assertTrue(
            exception.message!!.contains("offsetMinutesOfHour"),
            "Expected error message to contain 'offsetMinutesOfHour', but was: ${exception.message}"
        )
        assertFalse(
            exception.message!!.contains("minutesOfHour"),
            "Expected error message NOT to contain internal name 'minutesOfHour', but was: ${exception.message}"
        )
    }

    @Test
    fun testOffsetSecondsOfMinuteErrorMessage() {
        val format = DateTimeComponents.Format {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
            char(':')
            offsetSecondsOfMinute()
        }

        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                offsetHours = 5
                offsetMinutesOfHour = 30
                // Not setting offsetSecondsOfMinute
            }
        }

        assertTrue(
            exception.message!!.contains("offsetSecondsOfMinute"),
            "Expected error message to contain 'offsetSecondsOfMinute', but was: ${exception.message}"
        )
        assertFalse(
            exception.message!!.contains("secondsOfMinute"),
            "Expected error message NOT to contain internal name 'secondsOfMinute', but was: ${exception.message}"
        )
    }

    @Test
    fun testDayOfWeekErrorMessage() {
        val format = DateTimeComponents.Format {
            dayOfWeek(DayOfWeekNames.ENGLISH_ABBREVIATED)
        }

        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                // Not setting dayOfWeek
            }
        }

        assertTrue(
            exception.message!!.contains("dayOfWeek"),
            "Expected error message to contain 'dayOfWeek', but was: ${exception.message}"
        )
        assertFalse(
            exception.message!!.contains("isoDayOfWeek"),
            "Expected error message NOT to contain internal name 'isoDayOfWeek', but was: ${exception.message}"
        )
    }

    @Test
    fun testOriginalIssueScenario() {
        // This is the scenario from the original issue
        val readableFormat = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            alternativeParsing({}) {
                char(' ')
            }
            alternativeParsing(
                { timeZoneId() },
                { offset(UtcOffset.Formats.ISO) }
            ) {
                offsetHours()
                char(':')
                offsetMinutesOfHour()
                optional {
                    char(':')
                    offsetSecondsOfMinute()
                }
            }
        }

        val exception = assertFailsWith<IllegalStateException> {
            readableFormat.format {
                setDateTime(LocalDateTime(2024, 1, 15, 10, 30, 0))
                // Not setting offsetHours or timeZoneId
            }
        }

        // The error message should mention offsetHours, not totalHoursAbs
        assertFalse(
            exception.message!!.contains("totalHoursAbs"),
            "Expected error message NOT to contain internal name 'totalHoursAbs', but was: ${exception.message}"
        )
    }
}
"}

